--
-- Table structure for table `shipment_histories`
--

DROP TABLE IF EXISTS `shipment_histories`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `shipment_histories` (
  `id` int NOT NULL AUTO_INCREMENT,
  `shipment_order_id` int NOT NULL,
  `ghn_status` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `shipment_status` enum('ready_to_pick','picking','cancel','money_collect_picking','picked','storing','transporting','sorting','delivering','money_collect_delivering','delivered','delivery_fail','waiting_to_return','return','return_transporting','return_sorting','returning','return_fail','returned') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ready_to_pick',
  `occurred_at` timestamp NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `fk_shipment_histories_shipment_order` (`shipment_order_id`),
  CONSTRAINT `fk_shipment_histories_shipment_order` FOREIGN KEY (`shipment_order_id`) REFERENCES `shipment_orders` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=102 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

