  `type` enum('order','exchange_pickup','exchange_delivery') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `fk_shipment_orders_order` (`order_id`),
  KEY `fk_shipment_orders_exchange_request` (`exchange_request_id`),
  CONSTRAINT `fk_shipment_orders_exchange_request` FOREIGN KEY (`exchange_request_id`) REFERENCES `exchange_requests` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_shipment_orders_order` FOREIGN KEY (`order_id`) REFERENCES `orders` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=98 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
